    "worker_rights.topics.breaks.title": { en: "Rest and meal breaks", es: "Descansos y comidas" },
    "worker_rights.topics.breaks.body": {
        en: "10-minute paid rest break for every 4 hours worked. 30-minute unpaid meal break after 5 hours. Heat illness prevention required when temperature reaches 80°F: shade access, water, paid 10-minute cool-down breaks.",
        es: "Descanso pagado de 10 minutos por cada 4 horas trabajadas. Comida sin pagar de 30 minutos después de 5 horas. Prevención de enfermedad por calor obligatoria cuando la temperatura llega a 80°F: acceso a sombra, agua, descansos pagados de 10 minutos para refrescarse.",
    },
    "worker_rights.topics.transport.title": { en: "Transportation", es: "Transporte" },
    "worker_rights.topics.transport.body": {
        en: "If your employer provides transportation to the field, the vehicle must be inspected and the driver licensed. You're owed pay for travel time when employer-required.",
        es: "Si tu empleador provee transporte al campo, el vehículo debe estar inspeccionado y el conductor debe tener licencia. Te corresponde pago por tiempo de viaje cuando lo exige el empleador.",
    },
    "worker_rights.topics.retaliation.title": { en: "Retaliation protection", es: "Protección contra represalias" },
    "worker_rights.topics.retaliation.body": {
        en: "It's illegal for an employer to fire, demote, or threaten you for asking about wages, reporting unsafe conditions, joining a union, or filing a complaint. Documented retaliation can result in employer fines and back pay.",
        es: "Es ilegal que un empleador te despida, te degrade o te amenace por preguntar sobre salarios, reportar condiciones peligrosas, unirte a un sindicato o presentar una queja. Las represalias documentadas pueden resultar en multas al empleador y pago retroactivo.",
    },
    "worker_rights.topics.immigration.title": {
        en: "Status doesn't change rights",
        es: "Tu estatus no cambia tus derechos",
    },
    "worker_rights.topics.immigration.body": {
        en: "California labor law protects every farmworker regardless of immigration status. Wage claims and safety reports cannot be denied based on documentation. ICE cannot make a workplace arrest without a judicial warrant.",
        es: "La ley laboral de California protege a todo trabajador agrícola sin importar su estatus migratorio. Las reclamaciones de salario y reportes de seguridad no pueden ser negados por documentación. ICE no puede hacer un arresto en el lugar de trabajo sin una orden judicial.",
    },
    "worker_rights.help.eyebrow": { en: "Free legal help", es: "Ayuda legal gratuita" },
    "worker_rights.help.headline": { en: "You don't have to do this alone.", es: "No tienes que hacer esto solo." },
    "worker_rights.help.crla.name": {
        en: "California Rural Legal Assistance (CRLA)",
        es: "California Rural Legal Assistance (CRLA)",
    },
    "worker_rights.help.crla.body": {
        en: "Free legal services for farmworkers across California. Wage claims, housing, immigration, civil rights. Bilingual staff in every regional office.",
        es: "Servicios legales gratuitos para trabajadores agrícolas en todo California. Reclamaciones salariales, vivienda, inmigración, derechos civiles. Personal bilingüe en cada oficina regional.",
    },
    "worker_rights.help.crla.cta": { en: "crla.org · 1-800-337-0690", es: "crla.org · 1-800-337-0690" },
    "worker_rights.help.dlse.name": {
        en: "California Labor Commissioner (DLSE)",
        es: "Comisionado del Trabajo de California (DLSE)",
    },
    "worker_rights.help.dlse.body": {
        en: "File a wage claim if your employer hasn't paid you correctly. No fee to file. Your immigration status is never asked or shared.",
        es: "Presenta un reclamo de salario si tu empleador no te ha pagado correctamente. No hay tarifa por presentar. Nunca se pregunta ni se comparte tu estatus migratorio.",
    },
    "worker_rights.help.dlse.cta": { en: "dir.ca.gov/dlse · 1-833-LCO-INFO", es: "dir.ca.gov/dlse · 1-833-LCO-INFO" },
    "worker_rights.help.disclaimer": {
        en: "This page is informational, not legal advice. For your specific situation, contact a labor attorney or CRLA.",
        es: "Esta página es informativa, no es asesoría legal. Para tu situación específica, consulta a un abogado laboral o a CRLA.",
    },

