    "pricing_page.faq.q1.q": { en: "Is the worker side really always free?", es: "¿El lado del trabajador realmente siempre es gratis?" },
    "pricing_page.faq.q1.a": {
        en: "Yes. Workers will never pay AgConn for profile creation, job search, applications, or skills wallet access. Our worker-side cost is covered by employer subscriptions and partner contracts. We will not introduce a worker fee in the future.",
        es: "Sí. Los trabajadores nunca pagarán a AgConn por creación de perfil, búsqueda de empleo, postulaciones o acceso a la cartera de habilidades. Nuestro costo del lado del trabajador está cubierto por suscripciones de empleadores y contratos de socios. No introduciremos una tarifa para el trabajador en el futuro.",
    },
    "pricing_page.faq.q2.q": { en: "What happens to a posting if it doesn't fill in 30 days?", es: "¿Qué pasa con una publicación si no se llena en 30 días?" },
    "pricing_page.faq.q2.a": {
        en: "On the per-posting plan, you can renew an active posting once at no charge. After 60 days, a renewal is half-price. We do not auto-renew without explicit consent.",
        es: "En el plan por publicación, puedes renovar una publicación activa una vez sin costo. Después de 60 días, una renovación es a mitad de precio. No renovamos automáticamente sin consentimiento explícito.",
    },
    "pricing_page.faq.q3.q": { en: "Are there volume discounts on the per-posting plan?", es: "¿Hay descuentos por volumen en el plan por publicación?" },
    "pricing_page.faq.q3.a": {
        en: "Posting credits sold in packs of 10, 25, and 50 carry 10%, 18%, and 25% volume discounts respectively. Above 50 postings per year, the verified employer subscription is more economical.",
        es: "Los créditos de publicación vendidos en paquetes de 10, 25 y 50 llevan descuentos por volumen del 10%, 18% y 25% respectivamente. Por encima de 50 publicaciones por año, la suscripción de empleador verificado es más económica.",
    },
    "pricing_page.faq.q4.q": { en: "Do you accept Cal/OSBA or workforce-board funding?", es: "¿Aceptan financiamiento de Cal/OSBA o de juntas laborales?" },
    "pricing_page.faq.q4.a": {
        en: "Yes. We invoice in formats compatible with WIOA, CDFA grant disbursement, CalOSBA contracts, and standard 1099 reporting. Procurement teams can request our W-9, COI, and standard MSA at sales@agconn.com.",
        es: "Sí. Facturamos en formatos compatibles con WIOA, desembolso de subvenciones CDFA, contratos CalOSBA y reporte 1099 estándar. Los equipos de adquisiciones pueden solicitar nuestro W-9, COI y MSA estándar en sales@agconn.com.",
    },
    "pricing_page.faq.q5.q": { en: "Is there a free trial for the verified employer plan?", es: "¿Hay una prueba gratis para el plan de empleador verificado?" },
    "pricing_page.faq.q5.a": {
        en: "We offer a 30-day, no-charge trial of the verified employer plan that includes up to 5 postings and full applicant access. Cancel before day 30 with no charge. Sales team will not pursue you with calls.",
        es: "Ofrecemos una prueba de 30 días sin costo del plan de empleador verificado que incluye hasta 5 publicaciones y acceso completo a aplicantes. Cancela antes del día 30 sin cargo. El equipo de ventas no te perseguirá con llamadas.",
    },
